// Unsafe counter: two threads can increment simultaneously
class UnsafeCounter {
    private int count = 0;

    // Without synchronized, count++ has three steps
    // read, add, write — threads can interleave!
    public void increment() {
        count++;  // NOT atomic!
    }

    public int getCount() { return count; }
}

// Safe counter: synchronized prevents interleaving
class SafeCounter {
    private int count = 0;

    // synchronized ensures only one thread at a time
    public synchronized void increment() {
        count++;  // Now safe: one thread runs this fully
    }

    public synchronized int getCount() { return count; }
}

// Expected: SafeCounter always reaches 10000 with 1000 threads
// UnsafeCounter may reach 9987, 9992, etc. (race condition)
